前章までで中間コードをアセンブリに変換する部分は完成したので、本章からは後半部分である Jack 言語から中間コードへのコンパイラを書いていく。10 章 コンパイラ#1: 構文解析tokenizer を書くコードを token ごとに区切り、xml として出力するコードを書けばよい。こんなん半角スペースで分割してそれぞれの要素が何であるかを判定していけばいいだけやんとか思っていたが、よく考えたらこれは誤り (&quot;Hello world&quot; は半角スペースを含むが一つの token であるし、a[0] は半角スペースを含まないが複数の token を含んでいる)。なので、行ごとに一文字ずつ走査していき、 &quot; が発見されたら終わりが見つかるまで idx を進め、見つかったら STRING_CONST として token に加える symbol や半角文字が見つかったらある token の終わりとみなし、まだ出力されていない文字列を token として出力という操作が必要になる。import reimport pathlibimport sysimport tokenDicclass TokenObject: def __init__(self, token, token_type) -&amp;gt; None: self.token: str = token self.token_type: str = token_type self.before: &#39;list[str]&#39; = [] self.after: &#39;list[str]&#39; = [] def format(self) -&amp;gt; str: substitute_symbol_dic: str[str] = {&#39;&amp;lt;&#39;: &#39;&amp;amp;lt;&#39;, &#39;&amp;gt;&#39;: &#39;&amp;amp;gt;&#39;, &#39;&amp;amp;&#39;: &#39;&amp;amp;amp;&#39;} temp_token: str = self.token if self.token in substitute_symbol_dic.keys(): temp_token = substitute_symbol_dic[self.token] substitute_type_dic: str[str] = {&#39;string_const&#39;: &#39;stringConstant&#39;, &#39;int_const&#39;: &#39;integerConstant&#39;} temp_token_type = self.token_type.lower() if temp_token_type in substitute_type_dic.keys(): temp_token_type = substitute_type_dic[temp_token_type] output = f&#39;&amp;lt;{temp_token_type}&amp;gt; {temp_token} &amp;lt;/{temp_token_type}&amp;gt;&#39; if len(self.before) != 0: output = &#39;
&#39;.join(self.before) + &#39;
&#39; + output if len(self.after) != 0: output += &#39;
&#39; + &#39;
&#39;.join(self.after) return outputclass JackTokenizer: def __init__(self, p_file: str) -&amp;gt; None: self.p_file = p_file with open(p_file) as f: s: str = f.read() s = re.sub(r&#39;(//.*
|/\*.(.|\s)*?\*/)&#39;, &#39;
&#39;, s) # delete comments s = re.sub(r&#39; *
&#39;, &#39;
&#39;, s) # delete spaces at the end of lines self.lines: list[str] = s.split(&#39;
&#39;) self.lines = [line for line in self.lines if not re.match(r&#39;^\s*$&#39;, line)] self.current_line_num: int = 0 self.line_num: int = len(self.lines) self.output: str = &#39;&amp;lt;tokens&amp;gt;
&#39; self.token_objects: list[TokenObject] = [] def tokenizeLine(self, line: str) -&amp;gt; &#39;list[TokenObject]&#39;: token_objects: list[TokenObject] = [] token: str = &#39;&#39; token_type: str = &#39;&#39; len_of_list: int = len(line) idx: int = 0 beg_idx: int = 0 while idx &amp;lt; len_of_list: if line[idx] == &#39;&quot;&#39;: beg_idx = idx + 1 idx += 1 while idx &amp;lt; len_of_list: if line[idx] == &#39;&quot;&#39;: token_objects.append(TokenObject(line[beg_idx:idx], &#39;STRING_CONST&#39;)) beg_idx = idx + 1 break idx += 1 elif line[idx] in tokenDic.symbols: if beg_idx != idx: token = line[beg_idx:idx] token_type = self.tokenType(token) token_objects.append(TokenObject(token, token_type)) token_objects.append(TokenObject(line[idx], &#39;SYMBOL&#39;)) beg_idx = idx + 1 elif line[idx] == &#39; &#39; or line[idx] == &#39;	&#39;: if beg_idx != idx: token = line[beg_idx:idx] token_type = self.tokenType(token) token_objects.append(TokenObject(token, token_type)) beg_idx = idx + 1 idx += 1 return token_objects def tokenType(self, token) -&amp;gt; str: &quot;&quot;&quot; Determine the type of a given token &quot;&quot;&quot; if token in tokenDic.keywords: return &#39;KEYWORD&#39; elif token in tokenDic.symbols: return &#39;SYMBOL&#39; elif token.isdecimal(): if int(token) &amp;lt;= 32767: return &#39;INT_CONST&#39; else: SyntaxError(&#39;Value more than 32767 is not accepted&#39;) else: if token[0].isdecimal(): SyntaxError(&#39;Identifier starts with a number is not accepted&#39;) else: return &#39;IDENTIFIER&#39; def hasMoreLine(self) -&amp;gt; bool: return True if self.current_line_num &amp;lt; self.line_num else False def advance(self) -&amp;gt; bool: print(self.current_line_num) line: str = self.lines[self.current_line_num] token_objects = self.tokenizeLine(line) self.output += &#39;
&#39;.join([token_object.format() for token_object in token_objects]) + &#39;
&#39; self.token_objects.extend(token_objects) self.current_line_num += 1 def saveToFile(self) -&amp;gt; None: self.output += &#39;&amp;lt;/tokens&amp;gt;
&#39; self.path_w = f&#39;{self.p_file.parent}/{self.p_file.stem}T.xml&#39; with open(self.path_w, mode=&#39;w&#39;) as f: f.write(self.output)if __name__ == &#39;__main__&#39;: path: str = sys.argv[1] p_path: pathlib.Path = pathlib.Path(path) p_file_list: &#39;list[pathlib.Path]&#39; = [] if p_path.is_dir(): p_file_list = list(p_path.glob(&#39;**/*.jack&#39;)) else: p_file_list = [p_path] for p_file in p_file_list: tokenizer = JackTokenizer(p_file) while tokenizer.hasMoreLine(): tokenizer.advance() tokenizer.saveToFile()構文解析構文木を構築するため、再帰下降構文解析を行う (この言葉かっこよくて好きだ)。最初のトークンだけからトークンの種類を決定することができる文法を LL(1) といい、Jack 言語は概ねこれに従っている。例えば他の言語だと返り値無しの関数実行は a.run() とかになるが、Jack では do a.run() などと明示することによって、先読みすることなくこれが SubroutineCall であることが分かるようになっている。パーサを作るにあたっての留意点は括弧の処理である。例えば while 文 &#39;while&#39; &#39;(&#39; expression &#39;)&#39; &#39;{&#39; statements &#39;}&#39; という形で表されるが、expression や statements の中にも当然括弧が入りうるので、対応するものを正しく見つける必要がある。今回は、0 で初期化した変数を用意し、文字列を先頭から走査しつつ ( を見つけたら +1、) を見つけたら -1 していき、変数が 0 になったところを閉じ括弧とみなす方法を採用した。AtCoder の茶 diff くらいにありそうな問題だ。def findClosingBracket(self, start: int, end: int, open_c: str, close_c: str) -&amp;gt; int: bracket_cnt: int = 0 idx: int = start while idx &amp;lt;= end: if self.token_objects[idx].token == open_c: bracket_cnt += 1 elif self.token_objects[idx].token == close_c: bracket_cnt -= 1 if bracket_cnt == 0: return idx idx += 1 return -1基本的に p233-234 の仕様通りに書いていけばよいが、expression (式) の扱いでやや混乱した。expression は term (op term)* という形で表され、要は term が op を介して組み合わさっているという形 (具体的には、1 + 1 とか sum + a[0] + f(3) とか) なので、オペレータを見つけ次第 term として分割し、そのあとの文字列を再帰で処理することになる。全体的にゴリゴリの再帰を書くことになり結構疲れた。なんやかんやできたので達成感はある。import pathlibimport sysfrom tokenizer import TokenObject, JackTokenizerclass CompilationEngine: def __init__(self, token_objects: &#39;list[TokenObject]&#39;, p_file: str) -&amp;gt; None: self.token_objects = token_objects self.p_file = p_file self.statement_keyword_dic = { &#39;let&#39;: self.compileLet, &#39;if&#39;: self.compileIf, &#39;while&#39;: self.compileWhile, &#39;do&#39;: self.compileDo, &#39;return&#39;: self.compileReturn} self.output = &#39;&#39; pass def compile(self): print(len(self.token_objects) - 1) self.compileClasses(0, len(self.token_objects) - 1) def compileClasses(self, start: int, end_script: int): &quot;&quot;&quot; Compile classes (whole script) recursively &quot;&quot;&quot; if start &amp;gt;= end_script: return closing_class_idx = self.compileClass(start, end_script) print(self.token_objects[closing_class_idx].token) return self.compileClasses(closing_class_idx + 1, end_script) def compileClass(self, start: int, end_script: int): &quot;&quot;&quot; &#39;class&#39; className &#39;{&#39; classVarDec* subroutineDec* &#39;}&#39; ex) class Bar {...} &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;class&amp;gt;&#39;) print(self.token_objects[start + 1].token) closing_class_body_idx: int = self.findClosingBracket(start + 2, end_script, &#39;{&#39;, &#39;}&#39;) self.compileClassBody(start + 3, closing_class_body_idx - 1) self.token_objects[closing_class_body_idx].after.append(&#39;&amp;lt;/class&amp;gt;&#39;) return closing_class_body_idx def compileClassBody(self, start: int, end_class_body: int): &quot;&quot;&quot; classVarDec* subroutineDec* &#39;static int a; method int hoge (...) {...}&#39; &quot;&quot;&quot; if start &amp;gt;= end_class_body: return first_token: str = self.token_objects[start].token if first_token in [&#39;static&#39;, &#39;field&#39;]: end_idx: int = self.compileClassVarDec(start, end_class_body) else: end_idx: int = self.compileSubroutineDec(start, end_class_body) return self.compileClassBody(end_idx + 1, end_class_body) def compileClassVarDec(self, start: int, end_class_body: int) -&amp;gt; int: &quot;&quot;&quot; (&#39;static&#39; | &#39;field&#39;) type varName (&#39;,&#39; varName) * &#39;;&#39; ex) &#39;static int a;&#39; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;classVarDec&amp;gt;&#39;) print(self.token_objects[start + 1].token) idx: int = start while idx &amp;lt;= end_class_body: if self.token_objects[idx].token == &#39;;&#39;: break idx += 1 self.token_objects[idx].after.append(&#39;&amp;lt;/classVarDec&amp;gt;&#39;) return idx def compileSubroutineDec(self, start: int, end_class_body: int) -&amp;gt; int: &quot;&quot;&quot; (&#39;constructor&#39; | &#39;function&#39; | &#39;method&#39;) (&#39;void&#39; | type) subroutineName &#39;(&#39; parameterList &#39;)&#39; &#39;{&#39; subroutineBody &#39;}&#39; ex) &#39;method int hoge (...) {...}&#39; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;subroutineDec&amp;gt;&#39;) print(self.token_objects[start + 2].token) # compile &#39;(&#39; parameterList &#39;)&#39; closing_param_list_idx: int = self.findClosingBracket(start + 3, end_class_body, &#39;(&#39;, &#39;)&#39;) self.compileParameterList(start + 4, closing_param_list_idx - 1) # compile &#39;{&#39; subroutineBody &#39;}&#39; self.token_objects[closing_param_list_idx + 1].before.append(&#39;&amp;lt;subroutineBody&amp;gt;&#39;) closing_subr_body_idx: int = self.findClosingBracket(closing_param_list_idx + 1, end_class_body, &#39;{&#39;, &#39;}&#39;) self.token_objects[closing_subr_body_idx].after.append(&#39;&amp;lt;/subroutineBody&amp;gt;&#39;) self.compileSubroutineBody(closing_param_list_idx + 2, closing_subr_body_idx - 1) self.token_objects[closing_subr_body_idx].after.append(&#39;&amp;lt;/subroutineDec&amp;gt;&#39;) return closing_subr_body_idx def compileSubroutineBody(self, start: int, end_body: int) -&amp;gt; None: &quot;&quot;&quot; varDec* statements ex) &#39;var int a; let a = 1; return a;&#39; &quot;&quot;&quot; if start &amp;gt;= end_body: return first_token: str = self.token_objects[start].token if first_token == &#39;var&#39;: end_idx: int = self.compileVarDec(start, end_body) return self.compileSubroutineBody(end_idx + 1, end_body) else: self.token_objects[start].before.append(&#39;&amp;lt;statements&amp;gt;&#39;) end_idx: int = self.compileStatements(start, end_body) self.token_objects[end_body].after.append(&#39;&amp;lt;/statements&amp;gt;&#39;) return def compileSubroutineCall(self, start: int, end: int) -&amp;gt; None: &quot;&quot;&quot; subroutineName &#39;(&#39; expressionList &#39;)&#39; | (className | varName) &#39;.&#39; subroutineName &#39;(&#39; expressionList &#39;)&#39; ex) &#39;run()&#39;, &#39;a.run()&#39; &quot;&quot;&quot; # self.token_objects[start].before.append(&#39;&amp;lt;term&amp;gt;&#39;) idx: int = start while self.token_objects[idx].token != &#39;(&#39;: idx += 1 self.token_objects[idx].after.append(&#39;&amp;lt;expressionList&amp;gt;&#39;) closing_expression_list = self.findClosingBracket(idx, end, &#39;(&#39;, &#39;)&#39;) self.compileExpressionList(idx + 1, closing_expression_list - 1) self.token_objects[closing_expression_list].before.append(&#39;&amp;lt;/expressionList&amp;gt;&#39;) # self.token_objects[end].after.append(&#39;&amp;lt;/term&amp;gt;&#39;) def compileExpressionList(self, start: int, end: int) -&amp;gt; None: &quot;&quot;&quot; (expression (&#39;,&#39; expression)*)? ex) &#39;(a + 1, b)&#39; &quot;&quot;&quot; if start &amp;gt; end: return idx: int = start exp_start_idx: int = start while idx &amp;lt;= end: if self.token_objects[idx].token == &#39;,&#39;: self.compileExpression(exp_start_idx, idx - 1) exp_start_idx = idx + 1 idx += 1 self.compileExpression(exp_start_idx, end) def compileParameterList(self, start: int, end: int): &quot;&quot;&quot; ((type varName) (&#39;,&#39; type varName)*)? ex) &#39;int a, char c&#39;, &#39;&#39; &quot;&quot;&quot; if start &amp;gt; end: self.token_objects[end].after.append(&#39;&amp;lt;parameterList&amp;gt;&#39;) self.token_objects[start].before.append(&#39;&amp;lt;/parameterList&amp;gt;&#39;) else: self.token_objects[start].before.append(&#39;&amp;lt;parameterList&amp;gt;&#39;) self.token_objects[end].after.append(&#39;&amp;lt;/parameterList&amp;gt;&#39;) def compileVarDec(self, start: int, end_body: int) -&amp;gt; int: &quot;&quot;&quot; &#39;var&#39; type varName (&#39;,&#39; varname)* &#39;;&#39; ex) &#39;int a, b;&#39;; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;varDec&amp;gt;&#39;) idx: int = start while idx &amp;lt;= end_body: if self.token_objects[idx].token == &#39;;&#39;: break idx += 1 self.token_objects[idx].after.append(&#39;&amp;lt;/varDec&amp;gt;&#39;) return idx def compileStatements(self, start: int, end_statements: int) -&amp;gt; None: if start &amp;gt;= end_statements: return first_token: str = self.token_objects[start].token end_statement: int = self.statement_keyword_dic[first_token](start, end_statements) self.compileStatements(end_statement + 1, end_statements) def compileDo(self, start: int, end_statements: int) -&amp;gt; int: &quot;&quot;&quot; &#39;do&#39; subroutineCall &#39;;&#39; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;doStatement&amp;gt;&#39;) idx: int = start while idx &amp;lt;= end_statements: if self.token_objects[idx].token == &#39;;&#39;: break idx += 1 self.token_objects[idx].after.append(&#39;&amp;lt;/doStatement&amp;gt;&#39;) self.compileSubroutineCall(start + 1, idx - 1) return idx def compileLet(self, start: int, end_statements: int) -&amp;gt; int: &quot;&quot;&quot; &#39;let&#39; varname (&#39;[&#39; expression &#39;]&#39;)? &#39;=&#39; expression &#39;;&#39; ex) &#39;let a = 5;&#39;, &#39;let a[4] = b + 3;&#39; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;letStatement&amp;gt;&#39;) right_operand_start_idx: int = None if self.token_objects[start + 2].token == &#39;[&#39;: # if &#39;[&#39; expression &#39;]&#39; closing_expression_idx: int = self.findClosingBracket(start + 2, end_statements, &#39;[&#39;, &#39;]&#39;) self.compileExpression(start + 3, closing_expression_idx - 1) right_operand_start_idx = closing_expression_idx + 2 else: right_operand_start_idx = start + 3 idx: int = right_operand_start_idx while idx &amp;lt;= end_statements: if self.token_objects[idx].token == &#39;;&#39;: break idx += 1 self.token_objects[idx].after.append(&#39;&amp;lt;/letStatement&amp;gt;&#39;) self.compileExpression(right_operand_start_idx, idx - 1) return idx def compileWhile(self, start: int, end_statements: int) -&amp;gt; int: &quot;&quot;&quot; &#39;while&#39; &#39;(&#39; expression &#39;)&#39; &#39;{&#39; statements &#39;}&#39; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;whileStatement&amp;gt;&#39;) # (expression) closing_expression_idx: int = self.findClosingBracket(start + 1, end_statements, &#39;(&#39;, &#39;)&#39;) self.compileExpression(start + 2, closing_expression_idx - 1) # {statements} closing_statements_idx: int = self.findClosingBracket(closing_expression_idx + 1, end_statements, &#39;{&#39;, &#39;}&#39;) self.token_objects[closing_expression_idx + 2].before.append(&#39;&amp;lt;statements&amp;gt;&#39;) self.compileStatements(closing_expression_idx + 2, closing_statements_idx - 1) self.token_objects[closing_statements_idx - 1].after.append(&#39;&amp;lt;/statements&amp;gt;&#39;) self.token_objects[closing_statements_idx].after.append(&#39;&amp;lt;/whileStatement&amp;gt;&#39;) return closing_statements_idx def compileReturn(self, start: int, end_statements: int) -&amp;gt; int: &quot;&quot;&quot; &#39;return&#39; expression? &#39;;&#39; &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;returnStatement&amp;gt;&#39;) idx: int = start while idx &amp;lt;= end_statements: if self.token_objects[idx].token == &#39;;&#39;: break idx += 1 self.token_objects[idx].after.append(&#39;&amp;lt;/returnStatement&amp;gt;&#39;) if idx - start &amp;gt; 1: self.compileExpression(start + 1, idx - 1) return idx def findClosingBracket(self, start: int, end: int, open_c: str, close_c: str) -&amp;gt; int: bracket_cnt: int = 0 idx: int = start while idx &amp;lt;= end: if self.token_objects[idx].token == open_c: bracket_cnt += 1 elif self.token_objects[idx].token == close_c: bracket_cnt -= 1 if bracket_cnt == 0: return idx idx += 1 print(&#39;not found&#39;) def compileIf(self, start, end_statements) -&amp;gt; int: &quot;&quot;&quot; &#39;if&#39; &#39;(&#39; expression &#39;)&#39; &#39;{&#39; statements &#39;}&#39; (&#39;else&#39; &#39;{&#39; statements &#39;}&#39;)? &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;ifStatement&amp;gt;&#39;) # (expression) closing_expression_idx: int = self.findClosingBracket(start + 1, end_statements, &#39;(&#39;, &#39;)&#39;) self.compileExpression(start + 2, closing_expression_idx - 1) # {statements} closing_statements_idx: int = self.findClosingBracket(closing_expression_idx + 1, end_statements, &#39;{&#39;, &#39;}&#39;) self.token_objects[closing_expression_idx + 2].before.append(&#39;&amp;lt;statements&amp;gt;&#39;) self.compileStatements(closing_expression_idx + 2, closing_statements_idx - 1) self.token_objects[closing_statements_idx - 1].after.append(&#39;&amp;lt;/statements&amp;gt;&#39;) # else if (closing_statements_idx == end_statements) or ( self.token_objects[closing_statements_idx + 1].token != &#39;else&#39;): self.token_objects[closing_statements_idx].after.append(&#39;&amp;lt;/ifStatement&amp;gt;&#39;) return closing_statements_idx # {statements} closing_else_statements_idx: int = self.findClosingBracket(closing_statements_idx + 2, end_statements, &#39;{&#39;, &#39;}&#39;) self.token_objects[closing_statements_idx + 3].before.append(&#39;&amp;lt;statements&amp;gt;&#39;) self.compileStatements(closing_statements_idx + 3, closing_else_statements_idx - 1) self.token_objects[closing_else_statements_idx - 1].after.append(&#39;&amp;lt;/statements&amp;gt;&#39;) self.token_objects[closing_else_statements_idx].after.append(&#39;&amp;lt;/ifStatement&amp;gt;&#39;) return closing_else_statements_idx def compileExpression(self, start: int, end_exp: int) -&amp;gt; None: &quot;&quot;&quot; term (op term)* &quot;&quot;&quot; self.token_objects[start].before.append(&#39;&amp;lt;expression&amp;gt;&#39;) if start &amp;gt; end_exp: return idx: int = start while idx &amp;lt;= end_exp: # print(idx, end_exp) idx = self.compileTerm(idx, end_exp) idx += 1 if self.token_objects[idx].token in [&#39;+&#39;, &#39;-&#39;, &#39;*&#39;, &#39;/&#39;, &#39;&amp;amp;&#39;, &#39;|&#39;, &#39;&amp;lt;&#39;, &#39;&amp;gt;&#39;, &#39;=&#39;]: idx += 1 self.token_objects[end_exp].after.append(&#39;&amp;lt;/expression&amp;gt;&#39;) def compileTerm(self, start: int, end_exp: int) -&amp;gt; None: self.token_objects[start].before.append(&#39;&amp;lt;term&amp;gt;&#39;) first_token: str = self.token_objects[start].token print(first_token) end_idx: int = start if end_exp - start &amp;lt; 1: end_idx = end_exp # &#39;(&#39; expression &#39;)&#39; if first_token == &#39;(&#39;: closing_term: int = self.findClosingBracket(start, end_exp, &#39;(&#39;, &#39;)&#39;) self.compileExpression(start + 1, closing_term - 1) end_idx = closing_term # unaryOp elif first_token in [&#39;-&#39;, &#39;~&#39;]: closing_right_operand: int = self.compileTerm(start + 1, end_exp) end_idx = closing_right_operand # varName &#39;[&#39; expression &#39;]&#39; elif self.token_objects[start + 1].token == &#39;[&#39;: closing_term: int = self.findClosingBracket(start, end_exp, &#39;[&#39;, &#39;]&#39;) self.compileExpression(start + 2, closing_term - 1) end_idx = closing_term # subroutineName &#39;(&#39; expressionList &#39;)&#39; elif self.token_objects[start + 1].token == &#39;(&#39;: print(&#39;subroutine&#39;) closing_term: int = self.findClosingBracket(start + 1, end_exp, &#39;(&#39;, &#39;)&#39;) self.compileSubroutineCall(start, closing_term) end_idx = closing_term # (className | varName) &#39;.&#39; subroutineName &#39;(&#39; expressionList &#39;)&#39; elif self.token_objects[start + 1].token == &#39;.&#39;: print(&#39;subroutine&#39;) closing_term: int = self.findClosingBracket(start + 3, end_exp, &#39;(&#39;, &#39;)&#39;) self.compileSubroutineCall(start, closing_term) end_idx = closing_term self.token_objects[end_idx].after.append(&#39;&amp;lt;/term&amp;gt;&#39;) return end_idx def saveToFile(self) -&amp;gt; None: self.output += &#39;
