&#39; self.path_w = f&#39;{self.p_file.parent}/{self.p_file.stem}.xml&#39; with open(self.path_w, mode=&#39;w&#39;) as f: f.write(self.output)if __name__ == &#39;__main__&#39;: path: str = sys.argv[1] p_path: pathlib.Path = pathlib.Path(path) p_file_list: &#39;list[pathlib.Path]&#39; = [] if p_path.is_dir(): p_file_list = list(p_path.glob(&#39;**/*.jack&#39;)) else: p_file_list = [p_path] for p_file in p_file_list: print(p_file) tokenizer = JackTokenizer(p_file) while tokenizer.hasMoreLine(): tokenizer.advance() compiler = CompilationEngine(tokenizer.token_objects, p_file) compiler.compile() compiler.saveToFile()

前章で作成した VM translator に追加して、本章ではプログラム制御 (サブルーチンの呼び出しやメモリ割り当てなど) を実装していく。8 章 バーチャルマシン #2: プログラム制御プログラムフローコマンドまず面倒なのが if go-to コマンドのコンパイルである。これはスタックトップの値を pop して (これは前章までの内容でいける) 0 でなければ (TRUE であれば) 指定されたラベルに飛ぶ形になる。例えば以下のようなループを考える。label LOOP_START...if go-to LOOP_STARTこの vm コードを変換すると、以下のようなアセンブリを生成するようにする。(LOOP_START)...@SPA = M - 1D = M // まずはスタックトップの値を D に格納しておく@SP M = M - 1 // decement SP@TRUE1D;JNE// when D is zero (go downwards)...(TRUE1) // when D is not zero (jump to LOOP_START)@LOOP_START0;JMP関数呼び出しコマンド次にかなり厄介なのが関数呼び出しに伴う一連の実装とメモリ管理である。基本的に p178, p179 の図と疑似コードを見ながら慎重に書いていくのがよい。まず関数を呼び出す時点で以下の作業をしておく必要がある。 呼び出す関数の引数 n 個をまずプッシュする。 関数から出たあとに戻ってくるラベル (リターンアドレス) を指定。@return_address みたいにラベルを置いておくだけでよい。 呼び出し側の関数内の状態を保存するために、現在の LCL, ARG, THIS, THAT をこの順に push しておく。 ARG が指す位置を新しい関数向けに更新する。1 でプッシュした引数の 0 個目 (SP - n - 5) が新たな ARG になる。 LCL が指す位置を新しい関数向けに更新する。これは現在のスタックポインタの位置になる。 新しい関数のラベルに移動する。 この行に戻ってきたいので、(return-address) を置いておく。以上の作業が、call f n のコンパイル時に行われる。呼び出された関数 function f k の側では次の処理をすることになる。 関数名のラベルを置いておく。(f) としておけばよい。 k 個のローカル変数をすべて 0 で初期化する。pop constant 0 と pop local i を k 回繰り返せばよい。一番ややこしいのが関数からのリターンである。 もとの変数のリターンアドレスを適当な変数 @ret などに格納する。リターンアドレスが格納されている位置自体は *(LCL) - 5 である。 関数の戻り値を *(ARG) の位置に格納する。関数から出たあとは、返り値のアドレス = ARG が指しているアドレスとなる。 スタックポインタを *(ARG) + 1 の位置に変更する。関数から出たあとは、スタックポインタは返り値の次のアドレスを指すようになる。 THAT, THIS, ARG, LCL を元の値に復元する。 リターンアドレスにジャンプする。@ret; A = M; 0;JMP と問答無用で跳ぶようにする。以上の作業でハマったのが、1 を 4 より先に行っておくべきという点である。もしローカル引数が 0 個の場合 ARG が指すアドレスとリターンアドレスが格納されているメモリの位置が同じになってしまい、4 で ARG を更新するついでにリターンアドレスが更新されてすごいことになってしまう。これに気づくのに半日程度かかって悲しい気持ちに。ブートストラップコード同じディレクトリにあるすべての .vm に対して上記の作業を行い、一つの .asm ファイルを生成するようにする。ブートストラップコード (スタックポインタを 256 に設定する、call Sys.init する) を付け加えれば、おしまい！import reimport pathlibimport sysclass CodeWriter: def __init__(self, p_path: pathlib.Path) -&amp;gt; None: if p_path.is_dir(): self.path_w = f&#39;{p_path}/{p_path.stem}.asm&#39; else: self.path_w = p_path.with_suffix(&#39;.asm&#39;) print(self.path_w) self.dic = { &#39;local&#39;: &#39;@LCL&#39;, &#39;argument&#39;: &#39;@ARG&#39;, &#39;this&#39;: &#39;@THIS&#39;, &#39;that&#39;: &#39;@THAT&#39;, &#39;pointer&#39;: &#39;@3&#39;, &#39;temp&#39;: &#39;@5&#39;, } self.snippets = { &#39;increment_sp&#39;: [&#39;@SP&#39;, &#39;M = M + 1&#39;], &#39;decrement_sp&#39;: [&#39;@SP&#39;, &#39;M = M - 1&#39;], &#39;copy_d_to_stack_top&#39;: [&#39;@SP&#39;, &#39;A = M&#39;, &#39;M = D&#39;], &#39;from_stack_top_value_to_d&#39;: [&#39;@SP&#39;, &#39;A = M&#39;, &#39;D = M&#39;], &#39;update_address_to_top&#39;: [&#39;@SP&#39;, &#39;A = M&#39;], &#39;move_address_backward&#39;: [&#39;A = A - 1&#39;] } self.appendix: str = &#39;&#39; self.appendix_idx: int = 0 self.output: str = &#39;&#39; self.return_address_idx: int = 0 self.ret_idx: int = 0 self.addOutputLines([&#39;@256&#39;, &#39;D = A&#39;, &#39;@SP&#39;, &#39;M = D&#39;]) self.processCall(&#39;Sys.init&#39;, 0) def setFileName(self, p_file: pathlib.Path) -&amp;gt; None: self.filename: str = p_file.stem # get filename def processPush(self, arg1: str, arg2: str) -&amp;gt; None: if arg1 == &#39;constant&#39;: # Place num to stack top. ex) &#39;push constant 2&#39; self.addOutputLines([f&#39;@{arg2}&#39;, &#39;D = A&#39;]) elif arg1 == &#39;static&#39;: # Place the value of a symbol to stack top. ex) &#39;push static 1&#39; # Create the name of the symbol. ex) &#39;@filename.1&#39; self.addOutputLines([f&#39;@{self.filename}.{arg2}&#39;, &#39;D = M&#39;]) elif arg1 == &#39;pointer&#39; or arg1 == &#39;temp&#39;: # Place the address of this (pointer[0]) or that (pointer[1]) to stack top. ex) &#39;push pointer 1&#39;, or # Place the value of temp to stack top. ex) &#39;push temp 1&#39; self.addOutputLines([f&#39;@{arg2}&#39;, &#39;D = A&#39;, f&#39;{self.dic[arg1]}&#39;, &#39;A = A + D&#39;, &#39;D = M&#39;]) else: # argument, local, this, that # Place the value of the specified segment[idx] to stack top. ex) &#39;push argument 3&#39; self.addOutputLines([f&#39;@{arg2}&#39;, &#39;D = A&#39;, f&#39;{self.dic[arg1]}&#39;, &#39;A = M + D&#39;, &#39;D = M&#39;]) self.addOutputLines(self.snippets[&#39;copy_d_to_stack_top&#39;] + self.snippets[&#39;increment_sp&#39;]) def processPop(self, arg1: str, arg2: str) -&amp;gt; None: self.addOutputLines(self.snippets[&#39;decrement_sp&#39;] + self.snippets[&#39;from_stack_top_value_to_d&#39;]) if arg1 == &#39;constant&#39;: # Remove num from stack top. ex) &#39;pop constant 2&#39; # Is &#39;pop constant&#39; possible in .vm file? self.addOutputLines([f&#39;@{str(arg2)}&#39;, &#39;M = D&#39;]) elif arg1 == &#39;static&#39;: # Place the value of a stack top to a symbol. ex) &#39;pop static 1&#39; # Create the name of the symbol. ex) &#39;@filename.1&#39; self.addOutputLines([f&#39;@{self.filename}.{arg2}&#39;, &#39;M = D&#39;]) else: forward_A_arg2_times: list[str] = [&#39;A = A + 1&#39; for _ in range(int(arg2))] if arg1 == &#39;pointer&#39; or arg1 == &#39;temp&#39;: # Place the value of the stack top to this (pointer[0]) or that (pointer[1]). ex) &#39;pop pointer 1&#39;, or # Place the value of the stack top to temp. ex) &#39;pop temp 1&#39; self.addOutputLines([f&#39;{self.dic[arg1]}&#39;] + forward_A_arg2_times + [&#39;M = D&#39;]) else: # argument, local, this, that # Place the value of the stack top to specified segment[idx]. ex) &#39;pop argument 3&#39; self.addOutputLines([f&#39;{self.dic[arg1]}&#39;, &#39;A = M&#39;] + forward_A_arg2_times + [&#39;M = D&#39;]) def processArithmetric(self, command: str) -&amp;gt; None: if command == &#39;neg&#39; or command == &#39;not&#39;: self.addOutputLines(self.snippets[&#39;update_address_to_top&#39;] + self.snippets[&#39;move_address_backward&#39;]) self.addOutputLines([&#39;M = -M&#39;] if command == &#39;neg&#39; else [&#39;M = !M&#39;]) return self.addOutputLines( self.snippets[&#39;decrement_sp&#39;] + self.snippets[&#39;from_stack_top_value_to_d&#39;] # set the value of the second operand to D + self.snippets[&#39;move_address_backward&#39;]) # move address to the first operand if command == &#39;add&#39;: self.addOutputLines([&#39;M = M + D&#39;]) elif command == &#39;sub&#39;: self.addOutputLines([&#39;M = M - D&#39;]) elif command == &#39;and&#39;: self.addOutputLines([&#39;M = D &amp;amp; M&#39;]) elif command == &#39;or&#39;: self.addOutputLines([&#39;M = D | M&#39;]) else: # eq, gt, lt self.addOutputLines([&#39;D = M - D&#39;, f&#39;@TRUE{self.appendix_idx}&#39;]) if command == &#39;eq&#39;: self.addOutputLines([&#39;D;JEQ&#39;]) if command == &#39;gt&#39;: self.addOutputLines([&#39;D;JGT&#39;]) if command == &#39;lt&#39;: self.addOutputLines([&#39;D;JLT&#39;]) # If false, write 0 (false) to the top of the stuck self.addOutputLines([&#39;@SP&#39;, &#39;A = M - 1&#39;, &#39;M = 0&#39;, f&#39;(BACK{str(self.appendix_idx)})&#39;]) # If true, write -1 (true) to the top of the stuck self.addAppendixLines([f&#39;(TRUE{self.appendix_idx})&#39;, &#39;@SP&#39;, &#39;A = M - 1&#39;, &#39;M = -1&#39;, f&#39;@BACK{str(self.appendix_idx)}&#39;, &#39;0;JMP&#39;]) self.appendix_idx += 1 def processLabel(self, arg1: str) -&amp;gt; None: # ex) label loop self.addOutputLines([f&#39;({arg1})&#39;]) def processGoto(self, arg1: str) -&amp;gt; None: # ex) goto loop self.addOutputLines([f&#39;@{arg1}&#39;, &#39;0;JMP&#39;]) def processIfGoto(self, arg1: str) -&amp;gt; None: # ex) if-goto loop self.addOutputLines([&#39;@SP&#39;, &#39;A = M - 1&#39;, &#39;D = M&#39;] + self.snippets[&#39;decrement_sp&#39;] + [f&#39;@TRUE{self.appendix_idx}&#39;, &#39;D;JNE&#39;]) self.addAppendixLines([f&#39;(TRUE{self.appendix_idx})&#39;] + [f&#39;@{arg1}&#39;, &#39;0;JMP&#39;]) self.appendix_idx += 1 def processFunction(self, arg1: str, arg2: str) -&amp;gt; None: self.addOutputLines([f&#39;({arg1})&#39;]) for i in range(int(arg2)): self.processPush(&#39;constant&#39;, 0) self.processPop(&#39;local&#39;, i) def processReturn(self) -&amp;gt; None: updateAddressToOriginal = lambda label, times: self.addOutputLines( [&#39;@LCL&#39;, &#39;A = M&#39;] + [&#39;A = A - 1&#39; for _ in range(times)] + [&#39;D = M&#39;, f&#39;@{label}&#39;, &#39;M = D&#39;]) # Place return value to argument 0 updateAddressToOriginal(f&#39;ret{self.ret_idx}&#39;, 5) # ret = *(LCL - 5) self.processPop(&#39;argument&#39;, &#39;0&#39;) # *ARG = pop() self.addOutputLines([&#39;@ARG&#39;, &#39;D = M + 1&#39;, &#39;@SP&#39;, &#39;M = D&#39;]) # SP = ARG + 1 # updateAddressToOriginal(f&#39;ret&#39;, 5) # ret = *(LCL - 5) updateAddressToOriginal(&#39;THAT&#39;, 1) # THAT = *(LCL - 1) updateAddressToOriginal(&#39;THIS&#39;, 2) # THIS = *(LCL - 2) updateAddressToOriginal(&#39;ARG&#39;, 3) # ARG = *(LCL - 3) updateAddressToOriginal(&#39;LCL&#39;, 4) # LCL = *(LCL - 4) # self.addOutputLines([f&#39;@ret&#39;, &#39;A = M&#39;, &#39;0;JMP&#39;]) # goto ret self.addOutputLines([f&#39;@ret{self.ret_idx}&#39;, &#39;A = M&#39;, &#39;0;JMP&#39;]) # goto ret self.ret_idx += 1 def processCall(self, arg1: str, arg2: str): # self.processPush(&#39;constant&#39;, self.getLineNum() + 50 + int(arg2)) # push return_address # arg2 = max(int(arg2), 1) self.addOutputLines( [f&#39;@return_address_{self.return_address_idx}&#39;, &#39;D = A&#39;] + self.snippets[&#39;copy_d_to_stack_top&#39;] + self.snippets[&#39;increment_sp&#39;]) # push return-address pushLabel = lambda label: self.addOutputLines( [f&#39;@{label}&#39;, &#39;D = M&#39;] + self.snippets[&#39;copy_d_to_stack_top&#39;] + self.snippets[&#39;increment_sp&#39;]) pushLabel(&#39;LCL&#39;) # push LCL pushLabel(&#39;ARG&#39;) # push ARG pushLabel(&#39;THIS&#39;) # push THIS pushLabel(&#39;THAT&#39;) # push THAT self.addOutputLines([&#39;@SP&#39;, &#39;D = M&#39;] + [&#39;D = D - 1&#39; for _ in range(int(arg2) + 5)] + [&#39;@ARG&#39;, &#39;M = D&#39;]) # ARG = SP - arg2 - 5 self.addOutputLines([&#39;@SP&#39;, &#39;D = M&#39;, &#39;@LCL&#39;, &#39;M = D&#39;]) # LCL = SP self.processGoto(arg1) # goto f self.addOutputLines([f&#39;(return_address_{self.return_address_idx})&#39;]) self.return_address_idx += 1 def getLineNum(self) -&amp;gt; in