&#39;) self.lines = [line for line in self.lines if line != &#39;&#39;] # delete black lines self.line = self.lines[0] self.line_num = len(self.lines) self.current_line_num = 0 def commandType(self) -&amp;gt; str: &quot;&quot;&quot; Determine command type from a line &quot;&quot;&quot; command: str = self.line.split(&#39; &#39;)[0] if command == &#39;push&#39;: return &#39;C_PUSH&#39; elif command == &#39;pop&#39;: return &#39;C_POP&#39; elif command == &#39;label&#39;: return &#39;C_LABEL&#39; elif command == &#39;goto&#39;: return &#39;C_GOTO&#39; elif command == &#39;if-goto&#39;: return &#39;C_IF&#39; elif command == &#39;function&#39;: return &#39;C_FUNCTION&#39; elif command == &#39;return&#39;: return &#39;C_RETURN&#39; elif command == &#39;call&#39;: return &#39;C_CALL&#39; else: return &#39;C_ARITHMETIC&#39; def arg1(self) -&amp;gt; str: &quot;&quot;&quot; Returns the first argument &quot;&quot;&quot; tmp = self.line.split(&#39; &#39;) if len(tmp) != 1: # ex) &#39;local&#39; in &#39;push local 0&#39; return tmp[1] else: # When C_ARITHMETIC, the command itself is returned. ex) &#39;add&#39; return tmp[0] def arg2(self) -&amp;gt; str: &quot;&quot;&quot; Returns the second argument. This is called only when &#39;C_PUSH&#39;, &#39;C_POP&#39;, &#39;C_FUNCTION&#39;, or &#39;C_CALL&#39; &quot;&quot;&quot; # ex) &#39;0&#39; in &#39;push local 0&#39; tmp = self.line.split(&#39; &#39;) return tmp[2] def hasMoreCommands(self) -&amp;gt; bool: return True if self.current_line_num &amp;lt; self.line_num else False def advance(self) -&amp;gt; bool: print(self.current_line_num) self.line = self.lines[self.current_line_num] self.current_line_num += 1if __name__ == &#39;__main__&#39;: path: str = sys.argv[1] p_path: pathlib.Path = pathlib.Path(path) p_file_list: &#39;list[pathlib.Path]&#39; = [] if p_path.is_dir(): p_file_list = list(p_path.glob(&#39;**/*.vm&#39;)) else: p_file_list = [p_path] writer = CodeWriter(p_path) for p_file in p_file_list: parser = Parser(p_file) wri