前章でアセンブリ言語からバイナリへの変換ができるようになったため、次は一段階上がってコンパイラを書いていく。本書では Jack という簡易版 Java みたいな高水準言語の処理系を実装していくことになるのだが、これはまず中間コード (VM コード) を経てアセンブリ言語に変換される形式を採っている。7 章および 8 章では、VM コードをアセンブリ言語に変換する VM translator を作成する。7 章 バーチャルマシン #1: スタック操作メモリセグメント操作この章ではスタック操作を扱う。スタックポインタを SP とすると、例えば push constant 2 のように、定数の 2 をスタックのトップに追加する場合は以下のように変換すればよい。*(*(SP)) = 2 という操作をしたあとで、スタックポインタをインクリメントする形になる。@2D = A@SPA = MM = D@SPM = M + 1この VM には local というセグメントがあり、関数内で定義されたローカル変数は local セグメント (ベースアドレスは @LCL で指定されている) でアクセスできるようになる。例えば pop local 2 は *(*(@LCL) + 2) をスタックのトップにある値で更新する形になる。これをアセンブリ言語で書くと、次のような問題が発生する。// --- この前にスタックポインタをデクリメントする操作が入る ---@SPA = MD = M // ここでスタックトップの値を D に格納@2// ここでいつも通り D = 2 としたいが、そうすると上で格納した D の値が上書きされてしまう最初にこの本を読んだ際はなんか適当なシンボルを新たに定義してそこを一時的な退避場所として指定していたが、強い人のコード を見たところ @2 とせずに以下の方法で解決していた。なるほど確かに。@LCLA = A + 1A = A + 1 // 単に定数の回数だけ A をインクリメントすればよいM = D// --- この後にスタックをデクリメントする操作が入る ---また、この VM では pointer というセグメントが用意されており、pointer 0 は this を、pointer 1 は that を指す。例えば pop pointer 0 の場合だと this のベースアドレス (RAM[3] に格納されている値) をスタックの一番上にある値で更新することになる。ややこしいが、pop that 0 の場合は that が指しているアドレスの値 をスタックの一番上の値で更新することになるので注意。定数でもローカル変数でもポインタでもないものは static で宣言することになっており、例えば hoge.vm にある push static 3 は@hoge.3D = M// 以下、D をスタックにプッシュする処理のように変換される。これは何か static というセグメントが存在してそれの 3 番目ということではなく、単に一意になるようシンボルを命名しているだけである。スタック算術add, sub, and, or はいいとして問題は大小比較を行う演算子である。条件分岐を行い、true の場合はスタックトップに -1 を、false の場合は 0 を格納することになる。例えば eq の場合以下のようなコードを目指すことになる。@SPM = M - 1 // decrement SP@SPD = M // first operandA = A - 1D = M - D // second - first@TRUE1D;JEQ@SP // false A = M - 1M = 0(BACK1)...(TRUE1) // trueA = M - 1M = -1@BACK10;JMP2 項演算子ならスタックポインタをデクリメントする必要があるが、neg や not ではその必要がないので注意。完成したコード以上まとめると次のようになる。import reimport pathlibimport sysclass CodeWriter: def __init__(self, path) -&amp;gt; None: self.setFileName(path) self.dic = { &#39;local&#39;: &#39;@LCL&#39;, &#39;argument&#39;: &#39;@ARG&#39;, &#39;this&#39;: &#39;@THIS&#39;, &#39;that&#39;: &#39;@THAT&#39;, &#39;pointer&#39;: &#39;@3&#39;, &#39;temp&#39;: &#39;@5&#39;, } self.snippets = { &#39;increment_sp&#39;: [&#39;@SP&#39;, &#39;M = M + 1&#39;], &#39;decrement_sp&#39;: [&#39;@SP&#39;, &#39;M = M - 1&#39;], &#39;copy_d_to_stack_top&#39;: [&#39;@SP&#39;, &#39;A = M&#39;, &#39;M = D&#39;], &#39;from_stack_top_value_to_d&#39;: [&#39;@SP&#39;, &#39;A = M&#39;, &#39;D = M&#39;], &#39;update_address_to_top&#39;: [&#39;@SP&#39;, &#39;A = M&#39;], &#39;move_address_backward&#39;: [&#39;A = A - 1&#39;] } self.output: str = &#39;&#39; self.appendix: str = &#39;&#39; self.appendix_idx: int = 0 def setFileName(self, path) -&amp;gt; None: self.p_file = pathlib.Path(path) self.filename: str = self.p_file.stem # get filename self.path_w = self.p_file.with_suffix(&#39;.asm&#39;) def processPush(self, arg1: str, arg2: str) -&amp;gt; None: if arg1 == &#39;constant&#39;: # Place num to stack top. ex) &#39;push constant 2&#39; self.addOutputLines([f&#39;@{arg2}&#39;, &#39;D = A&#39;]) elif arg1 == &#39;static&#39;: # Place the value of a symbol to stack top. ex) &#39;push static 1&#39; # Create the name of the symbol. ex) &#39;@filename.1&#39; self.addOutputLines([f&#39;@{self.filename}.{arg2}&#39;, &#39;D = M&#39;]) elif arg1 == &#39;pointer&#39; or arg1 == &#39;temp&#39;: # Place the address of this (pointer[0]) or that (pointer[1]) to stack top. ex) &#39;push pointer 1&#39;, or # Place the value of temp to stack top. ex) &#39;push temp 1&#39; self.addOutputLines([f&#39;@{arg2}&#39;, &#39;D = A&#39;, f&#39;{self.dic[arg1]}&#39;, &#39;A = A + D&#39;, &#39;D = M&#39;]) else: # argument, local, this, that # Place the value of the specified segment[idx] to stack top. ex) &#39;push argument 3&#39; self.addOutputLines([f&#39;@{arg2}&#39;, &#39;D = A&#39;, f&#39;{self.dic[arg1]}&#39;, &#39;A = M + D&#39;, &#39;D = M&#39;]) self.addOutputLines(self.snippets[&#39;copy_d_to_stack_top&#39;] + self.snippets[&#39;increment_sp&#39;]) def processPop(self, arg1: str, arg2: str) -&amp;gt; None: self.addOutputLines(self.snippets[&#39;decrement_sp&#39;] + self.snippets[&#39;from_stack_top_value_to_d&#39;]) if arg1 == &#39;constant&#39;: # Remove num from stack top. ex) &#39;pop constant 2&#39; # Is &#39;pop constant&#39; possible in .vm file? self.addOutputLines([f&#39;@{str(arg2)}&#39;, &#39;M = D&#39;]) elif arg1 == &#39;static&#39;: # Place the value of a stack top to a symbol. ex) &#39;pop static 1&#39; # Create the name of the symbol. ex) &#39;@filename.1&#39; self.addOutputLines([f&#39;@{self.filename}.{arg2}&#39;, &#39;M = D&#39;]) else: forward_A_arg2_times: list[str] = [&#39;A = A + 1&#39; for _ in range(int(arg2))] if arg1 == &#39;pointer&#39; or arg1 == &#39;temp&#39;: # Place the value of the stack top to this (pointer[0]) or that (pointer[1]). ex) &#39;pop pointer 1&#39;, or # Place the value of the stack top to temp. ex) &#39;pop temp 1&#39; self.addOutputLines([f&#39;{self.dic[arg1]}&#39;] + forward_A_arg2_times + [&#39;M = D&#39;]) else: # argument, local, this, that # Place the value of the stack top to specified segment[idx]. ex) &#39;pop argument 3&#39; self.addOutputLines([f&#39;{self.dic[arg1]}&#39;, &#39;A = M&#39;] + forward_A_arg2_times + [&#39;M = D&#39;]) def processArithmetric(self, command: str) -&amp;gt; None: if command == &#39;neg&#39; or command == &#39;not&#39;: self.addOutputLines(self.snippets[&#39;update_address_to_top&#39;] + self.snippets[&#39;move_address_backward&#39;]) self.addOutputLines([&#39;M = -M&#39;] if command == &#39;neg&#39; else [&#39;M = !M&#39;]) return self.addOutputLines( self.snippets[&#39;decrement_sp&#39;] + self.snippets[&#39;from_stack_top_value_to_d&#39;] # set the value of the second operand to D + self.snippets[&#39;move_address_backward&#39;]) # move address to the first operand if command == &#39;add&#39;: self.addOutputLines([&#39;M = M + D&#39;]) elif command == &#39;sub&#39;: self.addOutputLines([&#39;M = M - D&#39;]) elif command == &#39;and&#39;: self.addOutputLines([&#39;M = D &amp;amp; M&#39;]) elif command == &#39;or&#39;: self.addOutputLines([&#39;M = D | M&#39;]) else: # eq, gt, lt self.addOutputLines([&#39;D = M - D&#39;, f&#39;@TRUE{self.appendix_idx}&#39;]) if command == &#39;eq&#39;: self.addOutputLines([&#39;D;JEQ&#39;]) if command == &#39;gt&#39;: self.addOutputLines([&#39;D;JGT&#39;]) if command == &#39;lt&#39;: self.addOutputLines([&#39;D;JLT&#39;]) # If false, write 0 (false) to the top of the stuck self.addOutputLines([&#39;@SP&#39;, &#39;A = M - 1&#39;, &#39;M = 0&#39;, f&#39;(BACK{str(self.appendix_idx)})&#39;]) # If true, write -1 (true) to the top of the stuck self.addAppendixLines([f&#39;(TRUE{self.appendix_idx})&#39;, &#39;@SP&#39;, &#39;A = M - 1&#39;, &#39;M = -1&#39;, f&#39;@BACK{str(self.appendix_idx)}&#39;, &#39;0;JMP&#39;]) self.appendix_idx += 1 def addOutputLines(self, lines: &#39;list[str]&#39;) -&amp;gt; None: self.output += &#39;
&#39;.join(lines) + &#39;
