 and delete black lines self.symbol_dic: dict[str, str] = config.symbol_dic self.clearCache() def clearCache(self) -&amp;gt; None: self.output: str = &quot;&quot; self.output_file_row_idx: int = 0 self.next_memory_idx: int = 16 def combertNumToBinaryStr(self, num: int) -&amp;gt; str: bin_str: str = format(num, &#39;b&#39;) return bin_str.rjust(16, &#39;0&#39;) def commandType(self) -&amp;gt; str: if self.line[0] == &#39;@&#39;: return &#39;A_COMMAND&#39; elif self.line[0] == &#39;(&#39;: return &#39;L_COMMAND&#39; else: return &#39;C_COMMAND&#39; def extractSymbol(self) -&amp;gt; str: # Extract symbol str from L_COMMAND or A_COMMAND return self.line.translate(str.maketrans({&#39;(&#39;: &#39;&#39;, &#39;)&#39;: &#39;&#39;, &#39;@&#39;: &#39;&#39;})) def processC(self) -&amp;gt; str: &quot;&quot;&quot; Process lines that start with neither &#39;@&#39; nor &#39;(&#39; &quot;&quot;&quot; c_parser_obj = CParser(self.line, self.binary_list) self.binary_list = c_parser_obj.process() return &#39;&#39;.join([str(i) for i in self.binary_list]) def processA(self) -&amp;gt; str: &quot;&quot;&quot; Process lines that start with &#39;@&#39; &quot;&quot;&quot; # Extract symbol str symbol_mnemonic: str = self.extractSymbol() # If the input is like &#39;@10&#39; if symbol_mnemonic.isdecimal(): # If the number is more than 32678, it is invalid as an ROM address and is regarded as a symbol if int(symbol_mnemonic) &amp;lt; 32768: bin_str = self.combertNumToBinaryStr(int(symbol_mnemonic)) return bin_str # If the input is a symbol like &#39;@i&#39; or &#39;@40000&#39; # If already exist in symbol dic if symbol_mnemonic in self.symbol_dic: return self.symbol_dic[symbol_mnemonic] # If new symbol bin_str = self.combertNumToBinaryStr(self.next_memory_idx) self.symbol_dic[symbol_mnemonic] = bin_str self.next_memory_idx += 1 return bin_str def processL(self) -&amp;gt; None: &quot;&quot;&quot; Process lines that start with &#39;(&#39; &quot;&quot;&quot; # Extract symbol str symbol_mnemonic: str = self.extractSymbol() # Convert the ROM address to binary string bin_str: str = self.combertNumToBinaryStr(self.output_file_row_idx) # Update symbol_dic self.symbol_dic[symbol_mnemonic] = bin_str def saveToFile(self) -&amp;gt; None: p_file = pathlib.Path(self.path) path_w: pathlib.Path = p_file.with_suffix(&#39;.hack&#39;) with open(path_w, mode=&#39;w&#39;) as f: f.write(self.output) def firstRun(self) -&amp;gt; None: # In the first run, only L_COMMAND is processed for line in self.lines: self.line = line if line[0] == &#39;(&#39;: self.processL() else: self.output_file_row_idx += 1 self.clearCache() return def secondRun(self) -&amp;gt; None: for line in self.lines: self.line = line self.binary_list: list[int] = [0 for _ in range(16)] command_type: str = self.commandType() if command_type == &#39;L_COMMAND&#39;: continue # If not L_COMMAND, one row will be added to the output file self.output_file_row_idx += 1 result: str = &#39;&#39; if command_type == &#39;C_COMMAND&#39;: result = self.processC() else: result = self.processA() self.output += result + &#39;
&#39; self.saveToFile() self.clearCache() returnif __name__ == &#39;__main__&#39;: path = sys.argv[1] parser_obj = Parser(path) parser_obj.firstRun() parser_obj.secondRun()デフォルトのシンボルテーブルや予約語処理用辞書は別ファイルにまとめて同ディレクトリに置いておくことにする。jump_dic = { &#39;null&#39;: &#39;000&#39;, &#39;JGT&#39;: &#39;001&#39;, &#39;JEQ&#39;: &#39;010&#39;, &#39;JGE&#39;: &#39;011&#39;, &#39;JLT&#39;: &#39;100&#39;, &#39;JNE&#39;: &#39;101&#39;, &#39;JLE&#39;: &#39;110&#39;, &#39;JMP&#39;: &#39;111&#39;}comp_dic = { &#39;D|A&#39;: &#39;010101&#39;, &#39;D&amp;amp;A&#39;: &#39;000000&#39;, &#39;A-D&#39;: &#39;000111&#39;, &#39;D-A&#39;: &#39;010011&#39;, &#39;D+A&#39;: &#39;000010&#39;, &#39;A+D&#39;: &#39;000010&#39;, &#39;A-1&#39;: &#39;110010&#39;, &#39;D-1&#39;: &#39;001110&#39;, &#39;A+1&#39;: &#39;110111&#39;, &#39;1+A&#39;: &#39;110111&#39;, &#39;D+1&#39;: &#39;011111&#39;, &#39;1+D&#39;: &#39;011111&#39;, &#39;-A&#39;: &#39;110011&#39;, &#39;-D&#39;: &#39;001111&#39;, &#39;!A&#39;: &#39;110001&#39;, &#39;!D&#39;: &#39;001101&#39;, &#39;A&#39;: &#39;110000&#39;, &#39;D&#39;: &#39;001100&#39;, &#39;-1&#39;: &#39;111010&#39;, &#39;1&#39;: &#39;111111&#39;, &#39;0&#39;: &#39;101010&#39;,}symbol_dic = { &#39;SP&#39;: &#39;0000000000000000&#39;, &#39;LCL&#39;: &#39;0000000000000001&#39;, &#39;ARG&#39;: &#39;0000000000000010&#39;, &#39;THIS&#39;: &#39;0000000000000011&#39;, &#39;THAT&#39;: &#39;0000000000000100&#39;, &#39;R0&#39;: &#39;0000000000000000&#39;, &#39;R1&#39;: &#39;0000000000000001&#39;, &#39;R2&#39;: &#39;0000000000000010&#39;, &#39;R3&#39;: &#39;0000000000000011&#39;, &#39;R4&#39;: &#39;0000000000000100&#39;, &#39;R5&#39;: &#39;0000000000000101&#39;, &#39;R6&#39;: &#39;0000000000000110&#39;, &#39;R7&#39;: &#39;0000000000000111&#39;, &#39;R8&#39;: &#39;0000000000001000&#39;, &#39;R9&#39;: &#39;0000000000001001&#39;, &#39;R10&#39;: &#39;0000000000001010&#39;, &#39;R11&#39;: &#39;0000000000001011&#39;, &#39;R12&#39;: &#39;0000000000001100&#39;, &#39;R13&#39;: &#39;0000000000001101&#39;, &#39;R14&#39;: &#39;0000000000001110&#39;, &#39;R15&#39;: &#39;0000000000001111&#39;, &#39;SCREEN&#39;: &#39;0100000000000000&#39;, &#39;KBD&#39;: &#39;0110000000000000&#39;}検証本章では、自作アセンブラが吐いたバイナリと付属の正しいアセンブラが吐いたバイナリの diff をみることによるデバッグが必要となる。少し作業を楽にするための tips として以下のようなものが有効であった。 付属のアセンブラが吐いたバイナリを git commit しておき、diff をエディタ上で確認できるようにしておく 以下のようなシェルスクリプトを置いておき、複数ファイルの出力をまとめてテストできるようにしておくpython -u &quot;Assembler.py&quot; ./add/Add.asmpython -u &quot;Assembler.py&quot; ./max/MaxL.asmpython -u &quot;Assembler.py&quot; ./max/Max.asmpython -u &quot;Assembler.py&quot; ./pong/PongL.asmpython -u &quot;Assembler.py&quot; ./pong/Pong.asmpython -u &quot;Assembler.py&quot; ./rect/RectL.asmpython -u &quot;Assembler.py&quot; ./rect/Rect.asm

動機最近 Amazon Prime Video で動画を複数人で同時視聴できるサービス (Watch Party) を使い始めた。再生しながら視聴者どうしでチャットができるという便利なものなのだが、ホストが Watch Party を終了させるとチャット履歴が消失するという問題がある。そこで、Watch Party のページをスクレイピングすることによりチャット履歴を記録したテキストファイルをダウンロードするスクリプトを書いた。実装 めちゃくちゃ意識が低くてアレだが、Watch Party にあるチャットウィンドウの要素を漁り、innerText からチマチマ情報を抽出していく (下記コードの create_chat_text() 部分)。これを text/plain の blob として作成したうえで、ダウンロードリンクをページに追加する。以上の作業を Tampermonkey の UserScript で行う。 ブラウザで Watch Party のリンクにアクセスした場合、まず参加設定 (チャットに用いるハンドルネームなど) に飛ばされ、入力後に再生画面およびチャットウィンドウが表示される仕様になっている (URL の変更はなし)。つまりアクセス直後はチャットウィンドウがまだ表示されていないため、要素を取得するためにはユーザが設定を終えて再生画面に遷移するのを待つ必要がある。これを実現するため、チャットウィンドウの要素が表示されるまで 1 秒おきに要素の取得を繰り返すという脳筋仕様にしてしまった (下記コードの wait_load() 部分)。絶対もっとマシな書き方があるはずなので、暇なときに改訂したい。// ==UserScript==// @name Watch Party// @namespace http://tampermonkey.net/// @version 0.1// @description Add button to download chat histories in Amazon Prime Watch Party// @author You// @match https://www.amazon.co.jp/gp/video/watchparty/*// @grant none// ==/UserScript==(function() { &#39;use strict&#39;; window.dl = function() { var blob = update_blob(); var newA = document.getElementById(&quot;download_link&quot;); newA.href = window.URL.createObjectURL(blob); } wait_load();})();var get_footer = function () { var footer = document.evaluate( &#39;//*[@id=&quot;embeddedChat&quot;]/div/div/div/div/div/div/div/div[3]&#39;, document, null, XPathResult.ORDERED_NODE_ITERATOR_TYPE, null ); return footer;};function create_chat_text() { var chat_text = &quot;&quot;; var chats_elems = document.evaluate( &#39;//*[@id=&quot;embeddedChat&quot;]/div/div/div/div/div/div/div/div[2]/div/div&#39;, document, null, XPathResult.ORDERED_NODE_ITERATOR_TYPE, null ); var this_elem = chats_elems.iterateNext(); Array.prototype.forEach.call(this_elem.children, function (elem) { var inner_text = elem.innerText; var splitted; if (elem.getAttribute(&quot;data-testid&quot;) === &quot;MessageClusterIncoming&quot;) { splitted = inner_text.split(&quot;
&quot;); if (splitted[3] != null) { for (var i = 3; i &amp;lt; splitted.length; i++) { chat_text += `${splitted[2]}	${splitted[0]}	${splitted[i]}
`; } } else { chat_text += `${splitted[2]}	${splitted[0]}	Stamp
`; } } else if (elem.getAttribute(&quot;data-testid&quot;) === &quot;MessageClusterOutgoing&quot;) { splitted = inner_text.split(&quot;
&quot;); if (splitted[1] != null) { var time = splitted[splitted.length - 1]; for (var i = 0; i &amp;lt; splitted.length - 1; i++) { chat_text += `${time}	Me	${splitted[i]}
`; } } else { chat_text += `${inner_text}	Me	Stamp
`; } } else { chat_text += inner_text === &quot;&quot; ? &quot;&quot; : `--- ${inner_text} ---
`; } }); return chat_text;}function update_blob() { var header_text = `Exported at ${new Date()}

`; var chat_text = create_chat_text(); var blob = new Blob([header_text + chat_text], { type: &quot;text/plain&quot; }); return blob;}function init() { var footer = get_footer(); var this_elem = footer.iterateNext(); var stamp = this_elem.firstChild; var newA = document.createElement(&quot;a&quot;); newA.id = &quot;download_link&quot;; newA.innerHTML = &quot;Download Chat History&quot;; newA.style.color = &#39;rgb(242, 244, 246)&#39;; newA.setAttribute(&quot;onclick&quot;, &quot;dl()&quot;); newA.download = &#39;&#39;; stamp.after(newA);}function wait_load() { var fn = function () { var footer = get_footer(); if (footer.iterateNext() != null) { console.log(&#39;found&#39;); clearInterval(id); init(); } else { console.log(&quot;not found&quot;); } }; var id = setInterval(fn, 1000);}できたものこれを Tampermonkey に追加すると以下のようになる。チャットウィンドウに表示された Download Chat History をクリックすると、以下のテキストファイルがダウンロードされる。Exported at Wed Dec 08 2021 17:10:40 GMT+0900 (日本標準時)--- ビデオを一時停止しています ------ hoge参加 ------ hogeが再生をコントロールします ---19 分 hoge Hello!--- hogeが退出しました ------ fuga参加 ------ fugaが再生をコントロールします ---19 分 Me Hello!19 分 Me How are you?今後やりたいこと ダウンロードボタンが追加されるのが気に入らないので、Tampermonkey ではなく Chrome 拡張機能として導入し、拡張機能のアイコンをクリックでダウンロードできるようにしたい 動画のタイトルを自動で取得しテキストファイルのファイル名に設定するようにしたい。動画再生中なら h1 h2 タグ抽出により取得できるのだが、終了後には要素ごと消えてしまう模様。何らかの方法で動画のメタデータを入手できればよいのだけど……
